#include <stdio.h>
#include <stdlib.h>
#define MAXN 500005
int parent[MAXN], rank[MAXN], population[MAXN];
int find(int x) { return parent[x] == x ? x : (parent[x] = find(parent[x])); }
void unionSet(int x, int y) { int rootX = find(x), rootY = find(y); if (rootX != rootY) { if (rank[rootX] > rank[rootY]) { parent[rootY] = rootX; } else if (rank[rootX] < rank[rootY]) { parent[rootX] = rootY; } else { parent[rootY] = rootX; rank[rootX]++; } }}
int main() {
    int N, M, Q;
    scanf("%d %d %d", &N, &M, &Q);
    for (int i = 1; i <= N; i++) {
        scanf("%d", &population[i]);
        parent[i] = i;
        rank[i] = 0;
    }
    for (int i = 1; i <= M; i++) {
        int x, y;
        scanf("%d %d", &x, &y);
        unionSet(x, y);
    }
    for (int i = 1; i <= Q; i++) {
        char query[10];
        scanf(" %s", query);
        if (query[0] == 'D') {
            int k;
            scanf("%d", &k);
            // remove the k-th edge
        } else if (query[0] == 'P') {
            int a, x;
            scanf("%d %d", &a, &x);
            population[a] = x;
        }
        int maxPopulation = 0;
        for (int j = 1; j <= N; j++) {
            int root = find(j);
            int populationSum = 0;
            for (int k = 1; k <= N; k++) {
                if (find(k) == root) {
                    populationSum += population[k];
                }
            }
            maxPopulation = (populationSum > maxPopulation) ? populationSum : maxPopulation;
        }
        printf("%d\n", maxPopulation);
    }
    return 0;
}

